INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (1, 190801, 2, 54, 2.801, 0.0, "受け取ることができる\n報酬があるようです\n確認してみてください", 20033, 3, -416.5, "2022/11/17 15:00:00", "カリン", "2030/01/01 14:59:59", 20033003);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (2, 190801, 2, 54, 0.0, 0.0, "報酬がもらえますよ！\nチェックしてみてください", 20033, 4, -416.5, "2022/11/17 15:00:00", "カリン", "2030/01/01 14:59:59", 20033004);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (1, 190801, 1, 57, 0.0, 0.0, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 20033, 5, -416.5, "2022/11/17 15:00:00", "カリン", "2030/01/01 14:59:59", 20033005);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (1, 190801, 2, 55, 5.506, 0.0, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 20033, 1, -363.0, "2022/11/17 15:00:00", "カリン", "2030/01/01 14:59:59", 20033006);
