INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (2, 190801, 1, 56, 1.539, 0.0, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 20033, 3, -363.0, "2022/11/17 15:00:00", "カリン", "2030/01/01 14:59:59", 20033008);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (2, 190801, 1, 56, 1.875, 0.0, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", 20033, 4, -363.0, "2022/11/17 15:00:00", "カリン", "2030/01/01 14:59:59", 20033009);
