INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (1, 190801, 2, 53, 3.414, 0.0, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 20048, 1, -416.5, "2023/12/18 15:00:00", "カリン", "2030/01/01 14:59:59", 20048001);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (1, 190801, 2, 53, 3.099, 0.0, "ミッションをクリアして、\n報酬をゲットしましょう！", 20048, 2, -416.5, "2023/12/18 15:00:00", "カリン", "2030/01/01 14:59:59", 20048002);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (1, 190801, 2, 54, 2.801, 0.0, "受け取ることができる\n報酬があるようです\n確認してみてください", 20048, 3, -416.5, "2023/12/18 15:00:00", "カリン", "2030/01/01 14:59:59", 20048003);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (2, 190801, 2, 54, 0.0, 0.0, "報酬がもらえますよ！\nチェックしてみてください", 20048, 4, -416.5, "2023/12/18 15:00:00", "カリン", "2030/01/01 14:59:59", 20048004);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (1, 190801, 1, 57, 0.0, 0.0, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 20048, 5, -416.5, "2023/12/18 15:00:00", "カリン", "2030/01/01 14:59:59", 20048005);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (1, 190801, 2, 55, 5.506, 0.0, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 20048, 1, -363.0, "2023/12/18 15:00:00", "カリン", "2030/01/01 14:59:59", 20048006);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (2, 190801, 1, 55, 1.216, 0.0, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", 20048, 2, -363.0, "2023/12/18 15:00:00", "カリン", "2030/01/01 14:59:59", 20048007);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (2, 190801, 1, 56, 1.539, 0.0, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 20048, 3, -363.0, "2023/12/18 15:00:00", "カリン", "2030/01/01 14:59:59", 20048008);
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (2, 190801, 1, 56, 1.875, 0.0, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", 20048, 4, -363.0, "2023/12/18 15:00:00", "カリン", "2030/01/01 14:59:59", 20048009);
