INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES (1, 190801, 1, 57, 0.0, 0.0, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 20060, 5, -416.5, "2025/01/16 15:00:00", "カリン", "2030/01/01 14:59:59", 20060005);
